sql:
SELECT trial_id, MAX(version_number) AS highest_version
FROM trial_versions
GROUP BY trial_id;

SELECT trial_id, MIN(sensor_value) AS min_sensor_reading
FROM sensor_values
GROUP BY trial_id;

SELECT DISTINCT users.user_name, users.email 
FROM users
JOIN trials ON users.user_id = trials.created_by;

SELECT 
    (SELECT COUNT(*) FROM trials) AS total_trials,
    (SELECT COUNT(*) FROM sensors) AS total_sensors;

SELECT sensor_value 
FROM trial_sensor_data 
WHERE trial_id = 1 AND sample_number = 1;

SELECT AVG(ts.sensor_value) AS average_sensor_value
FROM trial_sensor_data ts
WHERE ts.trial_id = 1;

SELECT trial_id, AVG(sensor_value) AS average_sensor_value
FROM trial_sensor_data
GROUP BY trial_id;

SELECT *
FROM trial_versions
WHERE created_by = 1;

SELECT COUNT(*) 
FROM trial_sensor_data 
WHERE trial_id = 0;

SELECT trials.*, users.user_name
FROM trials
INNER JOIN users ON trials.created_by = users.user_id;

SELECT tsd.data_id, tsd.trial_id, tsd.sensor_id, tsd.sensor_value, tsd.matching_condition, tsd.timestamp, tsd.unit
FROM trial_sensor_data AS tsd
JOIN matching_conditions AS mc ON tsd.matching_condition = mc.condition_name AND tsd.trial_id = mc.trial_id;

SELECT COUNT(sensor_value)
FROM sensor_values
WHERE trial_id = 0;

SELECT condition_name, COUNT(trial_id) AS number_of_trials
FROM matching_conditions
WHERE condition_name = 'S1O';
